209 |   async postRequest(endpoint, data) {
210 |     return new Promise((resolve, reject) => {
211 |       const url = new URL(endpoint, this.coordinatorUrl);
212 |       const postData = JSON.stringify(data);
213 | 
214 |       const options = {
215 |         hostname: url.hostname,
216 |         port: url.port || 3847,
217 |         path: url.pathname + url.search,
218 |         method: 'POST',
219 |         headers: {
220 |           'Content-Type': 'application/json',
221 |           'Content-Length': Buffer.byteLength(postData)
222 |         }
223 |       };
224 | 
225 |       const req = http.request(options, (res) => {
226 |         let responseData = '';
227 | 
228 |         res.on('data', (chunk) => {
229 |           responseData += chunk;
230 |         });
231 | 
232 |         res.on('end', () => {
233 |           try {
234 |             resolve(JSON.parse(responseData));
235 |           } catch (error) {
236 |             reject(error);
237 |           }
238 |         });
239 |       });
240 | 
241 |       req.on('error', reject);
242 |       req.write(postData);
243 |       req.end();
244 |     });
245 |   }
